package service.impl; import service.MemberService;import dao.MemberDao;import dao.impl.MemberDaoImpl;import model.Member;import java.util.*; public class MemberServiceImpl implements MemberService{MemberDao dao=new MemberDaoImpl(); public Member login(String a,String p){return dao.login(a,p);} public void register(Member m){dao.add(m);} public List<Member> findAll(){return dao.findAll();} public void save(Member m){if(m.getId()==0)dao.add(m);else dao.update(m);} public void delete(int id){dao.delete(id);} }
